public class SwitchExpr {
    public static void main(String[] args) {
        for (int i = 1; i <= 4; i++) {
            String result = switch (i) {
                case 1, 2 -> "low";
                case 3    -> "mid";
                default   -> "high";
            };
            System.out.println(i + ":" + result);
        }
    }
}
